 1→import { polygonArea, polygonCentroid, pointInPolygon } from './polygon';
 2→
 3→export function normalizeSlabBoundary(boundaryPoints = []) {
 4→  return boundaryPoints.map((point) => ({ x: point.x, y: point.y }));
 5→}
 6→
 7→export function slabArea(slab) {
 8→  return polygonArea(slab?.boundaryPoints || []);
 9→}
10→
11→export function slabCentroid(slab) {
12→  const boundaryPoints = slab?.boundaryPoints || [];
13→  if (boundaryPoints.length < 3) return { x: 0, y: 0 };
14→  return polygonCentroid(boundaryPoints);
15→}
16→
17→export function isValidSlabBoundary(boundaryPoints = []) {
18→  return boundaryPoints.length >= 3 && polygonArea(boundaryPoints) > 0;
19→}
20→
21→export function slabSvgPoints(slab) {
22→  return (slab?.boundaryPoints || []).map((point) => `${point.x},${point.y}`).join(' ');
23→}
24→
25→export function slabContainsPoint(slab, point) {
26→  const boundaryPoints = slab?.boundaryPoints || [];
27→  if (boundaryPoints.length < 3) return false;
28→  return pointInPolygon(point, boundaryPoints);
29→}
30→
31→export function getSlabRenderData(slab) {
32→  if (!slab || !isValidSlabBoundary(slab.boundaryPoints)) return null;
33→
34→  return {
35→    outline: normalizeSlabBoundary(slab.boundaryPoints),
36→    area: slabArea(slab),
37→    centroid: slabCentroid(slab),
38→    points: slabSvgPoints(slab),
39→  };
40→}
