 11→export function stairDirectionVector(stair) {
 12→  const angle = (stairDirectionAngle(stair) * Math.PI) / 180;
 13→  return normalize({
 14→    x: Math.cos(angle),
 15→    y: Math.sin(angle),
 16→  });
 17→}
 18→
 19→export function stairTotalRise(stair) {
 20→  return Math.max(0, (stair?.numberOfRisers || 0) * (stair?.riserHeight || 0));
 21→}
 22→
 23→export function stairRun(stair) {
 24→  return Math.max(0, (stair?.numberOfRisers || 0) * (stair?.treadDepth || 0));
 25→}
 26→
 27→export function stairOutline(stair) {
 28→  const startPoint = stair?.startPoint;
 29→  if (!startPoint) return [];
 30→
 31→  const direction = stairDirectionVector(stair);
 32→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return [];
 33→
 34→  const normal = perpendicular(direction);
 35→  const halfWidth = (stair?.width || 0) / 2;
 36→  const run = stairRun(stair);
 37→  const endPoint = add(startPoint, scale(direction, run));
 38→  const startOffset = scale(normal, halfWidth);
 39→  const endOffset = scale(normal, halfWidth);
 40→
 41→  return [
 42→    add(startPoint, startOffset),
 43→    add(endPoint, endOffset),
 44→    add(endPoint, scale(normal, -halfWidth)),
 45→    add(startPoint, scale(normal, -halfWidth)),
 46→  ];
 47→}
 48→
 49→export function stairTreadLines(stair) {
 50→  const startPoint = stair?.startPoint;
 51→  const risers = stair?.numberOfRisers || 0;
 52→  const treadDepth = stair?.treadDepth || 0;
 53→  const width = stair?.width || 0;
 54→  if (!startPoint || risers <= 0 || treadDepth <= 0 || width <= 0) return [];
 55→
 56→  const direction = stairDirectionVector(stair);
 57→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return [];
 58→
 59→  const normal = perpendicular(direction);
 60→  const halfWidth = width / 2;
 61→
 62→  return Array.from({ length: risers }, (_, index) => {
 63→    const treadStart = add(startPoint, scale(direction, treadDepth * index));
 64→    return {
 65→      start: add(treadStart, scale(normal, halfWidth)),
 66→      end: add(treadStart, scale(normal, -halfWidth)),
 67→    };
 68→  });
 69→}
 70→
 71→export function stairArrow(stair) {
 72→  const startPoint = stair?.startPoint;
 73→  if (!startPoint) return null;
 74→
 75→  const direction = stairDirectionVector(stair);
 76→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return null;
 77→
 78→  const run = stairRun(stair);
 79→  const centerOffset = scale(direction, run * 0.15);
 80→  const arrowStart = add(startPoint, centerOffset);
 81→  const arrowEnd = add(startPoint, scale(direction, run * 0.9));
 82→  const headLength = Math.min(250, Math.max(120, run * 0.08));
 83→  const normal = perpendicular(direction);
 84→
 85→  return {
 86→    start: arrowStart,
 87→    end: arrowEnd,
 88→    headA: add(arrowEnd, add(scale(direction, -headLength), scale(normal, headLength * 0.45))),
 89→    headB: add(arrowEnd, add(scale(direction, -headLength), scale(normal, -headLength * 0.45))),
 90→  };
 91→}
 92→
 93→export function stairBounds(stair) {
 94→  const outline = stairOutline(stair);
 95→  if (!outline.length) return null;
 96→
 97→  const xs = outline.map((point) => point.x);
 98→  const ys = outline.map((point) => point.y);
 99→  return {
100→    minX: Math.min(...xs),
101→    maxX: Math.max(...xs),
102→    minY: Math.min(...ys),
103→    maxY: Math.max(...ys),
104→  };
105→}
106→
107→export function stairContainsPoint(stair, point) {
108→  const outline = stairOutline(stair);
109→  if (outline.length < 3) return false;
110→  return pointInPolygon(point, outline);
111→}
112→
113→export function getStairRenderData(stair) {
114→  const outline = stairOutline(stair);
115→  if (outline.length < 3) return null;
116→
117→  const startPoint = stair.startPoint;
118→  const run = stairRun(stair);
119→  const direction = stairDirectionVector(stair);
120→  const endPoint = add(startPoint, scale(direction, run));
121→
122→  return {
123→    stair,
124→    outline,
125→    treads: stairTreadLines(stair),
126→    arrow: stairArrow(stair),
127→    totalRise: stairTotalRise(stair),
128→    run,
129→    angle: stairDirectionAngle(stair),
130→    startPoint,
131→    endPoint,
132→    center: midpoint(startPoint, endPoint),
133→    length: distance(startPoint, endPoint),
134→    bounds: stairBounds(stair),
135→  };
136→}
