  8→const EPSILON = 1e-6;
  9→const WALL_DIMENSION_GAP = 300;
 10→const ROOM_DIMENSION_INSET = 180;
 11→const OVERALL_CHAIN_GAP = 500;
 12→const OVERALL_TOTAL_GAP = 900;
 13→const ARROW_SIZE = 80;
 14→const VALUE_MERGE_TOLERANCE = 5;
 15→const MIN_DIMENSION_LENGTH = 100;
 16→
 17→function normalizeTextAngle(angleDeg) {
 18→  return angleDeg > 90 || angleDeg < -90 ? angleDeg + 180 : angleDeg;
 19→}
 20→
 21→function createArrowHead(tip, direction, size = ARROW_SIZE) {
 22→  const dir = normalize(direction);
 23→  const normal = perpendicular(dir);
 24→  const back = scale(dir, -size);
 25→  const side = scale(normal, size * 0.45);
 26→  return {
 27→    tip,
 28→    left: add(add(tip, back), side),
 29→    right: add(add(tip, back), scale(side, -1)),
 30→  };
 31→}
 32→
 33→function buildAlignedFigure(startPoint, endPoint, offset) {
 34→  const direction = normalize(subtract(endPoint, startPoint));
 35→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return null;
 36→
 37→  const normal = perpendicular(direction);
 38→  const offsetVector = scale(normal, offset);
 39→  const lineStart = add(startPoint, offsetVector);
 40→  const lineEnd = add(endPoint, offsetVector);
 41→  const angle = normalizeTextAngle(Math.atan2(direction.y, direction.x) * (180 / Math.PI));
 42→
 43→  return {
 44→    lineStart,
 45→    lineEnd,
 46→    extensionLines: [
 47→      { start: startPoint, end: lineStart },
 48→      { start: endPoint, end: lineEnd },
 49→    ],
 50→    textPosition: midpoint(lineStart, lineEnd),
 51→    textAngle: angle,
 52→    measurement: distance(startPoint, endPoint),
 53→    direction,
 54→  };
 55→}
 56→
 57→function buildHorizontalFigure(startPoint, endPoint, offset) {
 58→  const left = startPoint.x <= endPoint.x ? startPoint : endPoint;
 59→  const right = left === startPoint ? endPoint : startPoint;
 60→  const y = (startPoint.y + endPoint.y) / 2 + offset;
 61→  const lineStart = { x: left.x, y };
 62→  const lineEnd = { x: right.x, y };
 63→
 64→  return {
 65→    lineStart,
 66→    lineEnd,
 67→    extensionLines: [
 68→      { start: left, end: lineStart },
 69→      { start: right, end: lineEnd },
 70→    ],
 71→    textPosition: midpoint(lineStart, lineEnd),
 72→    textAngle: 0,
 73→    measurement: Math.abs(endPoint.x - startPoint.x),
 74→    direction: { x: 1, y: 0 },
 75→  };
 76→}
 77→
 78→function buildVerticalFigure(startPoint, endPoint, offset) {
 79→  const top = startPoint.y <= endPoint.y ? startPoint : endPoint;
 80→  const bottom = top === startPoint ? endPoint : startPoint;
 81→  const x = (startPoint.x + endPoint.x) / 2 + offset;
 82→  const lineStart = { x, y: top.y };
 83→  const lineEnd = { x, y: bottom.y };
 84→
 85→  return {
 86→    lineStart,
 87→    lineEnd,
 88→    extensionLines: [
 89→      { start: top, end: lineStart },
 90→      { start: bottom, end: lineEnd },
 91→    ],
 92→    textPosition: midpoint(lineStart, lineEnd),
 93→    textAngle: 90,
 94→    measurement: Math.abs(endPoint.y - startPoint.y),
 95→    direction: { x: 0, y: 1 },
 96→  };
 97→}
