 276→function parseColor(styleValue) {
 277→  if (!styleValue || styleValue === 'none') return null;
 278→  const normalized = String(styleValue).trim();
 279→
 280→  if (normalized.startsWith('#')) {
 281→    const hex = normalized.slice(1);
 282→    const chunks = hex.length === 3
 283→      ? hex.split('').map((value) => value + value)
 284→      : [hex.slice(0, 2), hex.slice(2, 4), hex.slice(4, 6)];
 285→    return chunks.map((value) => parseInt(value, 16) / 255);
 286→  }
 287→
 288→  const rgb = normalized.match(/rgba?\(([^)]+)\)/i);
 289→  if (rgb) {
 290→    const values = rgb[1].split(',').map((value) => Number.parseFloat(value.trim()));
 291→    return values.slice(0, 3).map((value) => value / 255);
 292→  }
 293→
 294→  return null;
 295→}
