 327→function lineCapCode(value) {
 328→  if (value === 'round') return 1;
 329→  if (value === 'square') return 2;
 330→  return 0;
 331→}
 332→
 333→function lineJoinCode(value) {
 334→  if (value === 'round') return 1;
 335→  if (value === 'bevel') return 2;
 336→  return 0;
 337→}
