  1→import { doorOutlineOnWall, positionOnWall, projectPointOnWall, wallAngle, wallLength, wallOutline, windowOutlineOnWall } from '@/geometry/wallGeometry';
  2→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  3→
  4→const EPSILON = 1e-6;
  5→
  6→function clamp(value, min, max) {
  7→  return Math.max(min, Math.min(max, value));
  8→}
  9→
 10→function buildOpeningDescriptor(kind, source, context) {
 11→  const outlineInfo = kind === 'door'
 12→    ? doorOutlineOnWall(context.sourceWall, source)
 13→    : windowOutlineOnWall(context.sourceWall, source);
 14→
 15→  const sourceCenterAlong = projectPointOnWall(context.sourceWall, outlineInfo.center);
 16→  const sourceStartAlong = sourceCenterAlong - source.width / 2;
 17→  const sourceEndAlong = sourceCenterAlong + source.width / 2;
 18→  const clippedSourceStartAlong = clamp(sourceStartAlong, context.trimStartAlong, context.trimEndAlong);
 19→  const clippedSourceEndAlong = clamp(sourceEndAlong, context.trimStartAlong, context.trimEndAlong);
 20→  const visibleWidth = clippedSourceEndAlong - clippedSourceStartAlong;
 21→
 22→  const baseElevation = context.wallBase + (source.sillHeight ?? 0);
 23→  const topElevation = baseElevation + (source.height ?? 0);
 24→  const visibleBaseElevation = clamp(baseElevation, context.wallBase, context.wallTop);
 25→  const visibleTopElevation = clamp(topElevation, context.wallBase, context.wallTop);
 26→  const visibleHeight = visibleTopElevation - visibleBaseElevation;
 27→
 28→  if (visibleWidth <= EPSILON || visibleHeight <= EPSILON) {
 29→    return null;
 30→  }
 31→
 32→  const startAlong = clippedSourceStartAlong - context.trimStartAlong;
 33→  const endAlong = clippedSourceEndAlong - context.trimStartAlong;
 34→  const centerAlong = (startAlong + endAlong) / 2;
 35→  const startPoint = positionOnWall(context.renderWall, startAlong);
 36→  const endPoint = positionOnWall(context.renderWall, endAlong);
 37→  const centerPoint = positionOnWall(context.renderWall, centerAlong);
 38→
 39→  return {
 40→    id: source.id,
 41→    kind,
 42→    type: source.type || (kind === 'window' ? 'standard' : 'swing'),
 43→    openDirection: source.openDirection || 'left',
 44→    wallId: context.wall.id,
 45→    sourceId: source.id,
 46→    angle: wallAngle(context.renderWall),
 47→    wallThickness: context.renderWall.thickness,
 48→    width: source.width,
 49→    height: source.height ?? 0,
 50→    sillHeight: source.sillHeight ?? 0,
 51→    startAlong,
 52→    endAlong,
 53→    centerAlong,
 54→    visibleWidth,
 55→    visibleBaseElevation,
 56→    visibleTopElevation,
 57→    visibleHeight,
 58→    startPoint,
 59→    endPoint,
 60→    centerPoint,
 61→    outline: wallOutline({
 62→      start: startPoint,
 63→      end: endPoint,
 64→      thickness: context.renderWall.thickness,
 65→    }),
 66→    metadata: {
 67→      wallId: context.wall.id,
 68→      floorId: context.floorId,
 69→      sourceStartAlong,
 70→      sourceEndAlong,
 71→      clippedSourceStartAlong,
 72→      clippedSourceEndAlong,
 73→    },
 74→  };
 75→}
 76→
 77→export function buildWallPreviewContext(floor, wall, floorLevel) {
 78→  const wallRenderData = getWallRenderData(wall, floor.columns || []);
 79→  const sourceWall = wallRenderData.wall;
 80→  const renderWall = wallRenderData.renderWall;
 81→  const trimStartAlong = projectPointOnWall(sourceWall, renderWall.start);
 82→  const trimEndAlong = projectPointOnWall(sourceWall, renderWall.end);
 83→  const context = {
 84→    floorId: floor.id,
 85→    wall,
 86→    sourceWall,
 87→    renderWall,
 88→    wallRenderData,
 89→    trimStartAlong,
 90→    trimEndAlong,
 91→    renderLength: wallLength(renderWall),
 92→    wallBase: floorLevel,
 93→    wallTop: floorLevel + (wall.height ?? 0),
 94→  };
 95→
 96→  const openings = [
 97→    ...(floor.doors || []).filter((item) => item.wallId === wall.id).map((door) => (
 98→      buildOpeningDescriptor('door', door, context)
 99→    )),
100→    ...(floor.windows || []).filter((item) => item.wallId === wall.id).map((windowItem) => (
101→      buildOpeningDescriptor('window', windowItem, context)
102→    )),
103→  ]
104→    .filter(Boolean)
105→    .sort((left, right) => left.startAlong - right.startAlong);
106→
107→  return {
108→    ...context,
109→    openings,
110→  };
111→}
112→
113→export function buildWallPreviewContexts(floor, floorLevel) {
114→  return (floor.walls || []).map((wall) => buildWallPreviewContext(floor, wall, floorLevel));
115→}
116→
117→export function buildWallSolidSegments(context) {
118→  if (context.renderLength <= EPSILON || context.wallTop - context.wallBase <= EPSILON) {
119→    return [];
120→  }
121→
122→  const segments = [];
123→  let cursor = 0;
124→  let segmentIndex = 0;
125→
126→  const pushSegment = (startAlong, endAlong, baseElevation, topElevation) => {
127→    if (endAlong - startAlong <= EPSILON) return;
128→    if (topElevation - baseElevation <= EPSILON) return;
129→
130→    segmentIndex += 1;
131→    segments.push({
132→      id: `${context.wall.id}-segment-${segmentIndex}`,
133→      wallId: context.wall.id,
134→      floorId: context.floorId,
135→      startPoint: positionOnWall(context.renderWall, startAlong),
136→      endPoint: positionOnWall(context.renderWall, endAlong),
137→      thickness: context.renderWall.thickness,
138→      baseElevation,
139→      topElevation,
140→    });
141→  };
142→
143→  for (const opening of context.openings) {
144→    const openingStart = Math.max(cursor, opening.startAlong);
145→    const openingEnd = Math.max(openingStart, opening.endAlong);
146→
147→    pushSegment(cursor, openingStart, context.wallBase, context.wallTop);
148→
149→    if (opening.visibleBaseElevation > context.wallBase + EPSILON) {
150→      pushSegment(
151→        openingStart,
152→        openingEnd,
153→        context.wallBase,
154→        Math.min(opening.visibleBaseElevation, context.wallTop)
155→      );
156→    }
157→
158→    if (opening.visibleTopElevation < context.wallTop - EPSILON) {
159→      pushSegment(
160→        openingStart,
161→        openingEnd,
162→        Math.max(opening.visibleTopElevation, context.wallBase),
163→        context.wallTop
164→      );
165→    }
166→
167→    cursor = Math.max(cursor, openingEnd);
168→  }
169→
170→  pushSegment(cursor, context.renderLength, context.wallBase, context.wallTop);
171→  return segments;
172→}
